var isValid = function(s) {
    const stack = [];
    for (const ch of s) {
        if (ch === 'c') {
            const n = stack.length;
            if (n >= 2 && stack[n - 1] === 'b' && stack[n - 2] === 'a') {
                stack.pop();
                stack.pop();
            } else {
                return false;
            }
        } else {
            stack.push(ch);
        }
    }
    return stack.length === 0;
};
